{{Template shortcut|rdf}}
{{Lua|Module:Redirect-distinguish-for}}
Redirection notice that has both "not to be confused with" and "for Use".

== Usage ==

* {{tlx|Redirect-distinguish-for|REDIRECT|PAGE2|USE3|PAGE3}} &rarr; {{Redirect-distinguish-for|REDIRECT|PAGE2|USE3|PAGE3}}
* {{tlx|Redirect-distinguish-for|REDIRECT|PAGE2|<nowiki/>|PAGE3}} &rarr; {{Redirect-distinguish-for|REDIRECT|PAGE2||PAGE3}}
* {{tlx|Redirect-distinguish-for|REDIRECT|PAGE2|USE3}} &rarr; {{Redirect-distinguish-for|REDIRECT|PAGE2|USE3}}
* {{tlx|Redirect-distinguish-for|REDIRECT|PAGE2}} &rarr; {{Redirect-distinguish-for|REDIRECT|PAGE2}}

== TemplateData ==
{{TemplateData header}}
<templatedata>
{
	"params": {
		"1": {
			"label": "Redirecting page",
			"description": "Name of page that redirects here",
			"type": "wiki-page-name",
			"required": true
		},
		"2": {
			"label": "Similar page",
			"description": "Page to indicate as \"not to be confused with\"",
			"type": "wiki-page-name",
			"required": true
		},
		"3": {
			"label": "Use",
			"description": "Displayed as: For Use, see ... If left empty, defaults to For other uses, see ...",
			"type": "content",
			"suggested": true
		},
		"4": {
			"label": "Target",
			"description": "Page to link to. Default is [[PAGENAME (disambiguation)]].",
			"type": "wiki-page-name",
			"suggested": true
		}
	},
	"description": "Redirection notice that has both \"not to be confused with\" and \"for Use\"",
	"format": "inline"
}
</templatedata>

